1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	
17	function countByType(items: any[]): Record<string, number> {
18	  const counts: Record<string, number> = {};
19	  for (const item of items) {
20	    counts[item.type] = (counts[item.type] ?? 0) + 1;
21	  }
22	  return counts;
23	}
24	
25	function calculateBasePremium(typeCounts: Record<string, number>): number {
26	  let total = 0;
27	  for (const [type, count] of Object.entries(typeCounts)) {
28	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
29	      total += BLOCK_PREMIUM;
30	    } else {
31	      total += count * (BASE_PREMIUM[type] ?? 0);
32	    }
33	  }
34	  return total;
35	}
36	
37	function calculateQuotePremium(items: any[]): number {
38	  const typeCounts = countByType(items);
39	  const basePremium = calculateBasePremium(typeCounts);
40	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
41	  return Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
42	}
43	
44	export function processScenario(scenario: any): unknown {
45	  const results = scenario.steps.map((step: any) => ({
46	    premium: calculateQuotePremium(step.items),
47	  }));
48	
49	  return { results };
50	}
